  createdAt: string;
  items: Evidence[];
};

export type Artifact = {
  id: string;
  topicId: string;
  type: ArtifactType;
  storage: 'memory' | 'file';
  uri: string;
  createdAt: string;
};

export const createEvidenceSet = (topicId: string): EvidenceSet => ({
  id: createId('es'),
  topicId,
  createdAt: nowIso(),
  items: []
